import React, { useState, useEffect } from 'react';
import { 
  ShoppingBag, ShoppingCart, LogOut, User, MapPin, 
  Package, Clock, Plus, Trash2, ChevronRight, 
  Settings, CreditCard, Bell, ShieldCheck
} from 'lucide-react';
import { authAPI, addressAPI } from '../api';

const ProfilePage = ({
  user, cart, orders, profileData, setProfileData,
  setCurrentPage, handleLogout, setError, loadOrders,
  loading, setLoading
}) => {
  const [editMode, setEditMode] = useState(false);
  const [loadingProfile, setLoadingProfile] = useState(false);
  const [activeTab, setActiveTab] = useState('profile'); // New state for tabbed navigation

  useEffect(() => {
    fetchAddresses();
    fetchProfile();
    if (user) fetchOrders();
  }, [user]);

  // ... (Keep all your existing fetch/save logic here - no changes needed to functions)
  const fetchProfile = async () => { /* your existing code */ };
  const fetchAddresses = async () => { /* your existing code */ };
  const handleSaveProfile = async () => { /* your existing code */ };
  const fetchOrders = async () => { await loadOrders(); };

  return (
    <div className="min-h-screen bg-[#f8fafc]">
      {/* MODERN COMPACT HEADER */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setCurrentPage('products')}>
            <div className="w-8 h-8 bg-teal-600 rounded-lg flex items-center justify-center">
              <ShoppingBag className="w-5 h-5 text-white" />
            </div>
            <span className="text-xl font-black bg-gradient-to-r from-teal-600 to-cyan-600 bg-clip-text text-transparent">
              ShopAI
            </span>
          </div>

          <div className="flex items-center gap-4">
            <button onClick={() => setCurrentPage('cart')} className="relative p-2 text-slate-600 hover:bg-slate-100 rounded-full transition-colors">
              <ShoppingCart className="w-5 h-5" />
              {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-teal-600 text-white text-[10px] font-bold rounded-full w-4 h-4 flex items-center justify-center">
                  {cart.length}
                </span>
              )}
            </button>
            <button onClick={handleLogout} className="flex items-center gap-2 px-4 py-2 text-sm font-semibold text-rose-600 hover:bg-rose-50 rounded-lg transition-colors">
              <LogOut className="w-4 h-4" />
              <span className="hidden sm:inline">Sign Out</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        <div className="grid lg:grid-cols-12 gap-8">

          {/* LEFT COLUMN: USER AVATAR & NAVIGATION */}
          <div className="lg:col-span-4 xl:col-span-3 space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 text-center">
              <div className="relative inline-block mb-4">
                <div className="w-24 h-24 bg-gradient-to-tr from-teal-500 to-cyan-400 rounded-2xl flex items-center justify-center text-white text-3xl font-bold shadow-inner">
                  {profileData.fullName?.[0] || 'U'}
                </div>
                <div className="absolute -bottom-2 -right-2 bg-white p-1.5 rounded-lg shadow-md border border-slate-100">
                  <ShieldCheck className="w-5 h-5 text-teal-500" />
                </div>
              </div>
              <h2 className="text-xl font-bold text-slate-900">{profileData.fullName || 'User'}</h2>
              <p className="text-sm text-slate-500 mb-6">{profileData.email}</p>

              <div className="grid grid-cols-2 gap-2 py-4 border-t border-slate-100">
                <div className="text-center">
                  <p className="text-lg font-bold text-slate-900">{orders.length}</p>
                  <p className="text-[10px] uppercase tracking-wider font-bold text-slate-400">Orders</p>
                </div>
                <div className="text-center border-l border-slate-100">
                  <p className="text-lg font-bold text-slate-900">{profileData.addresses?.length || 0}</p>
                  <p className="text-[10px] uppercase tracking-wider font-bold text-slate-400">Addresses</p>
                </div>
              </div>
            </div>

            {/* SIDE NAV */}
            <nav className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
              {[
                { id: 'profile', label: 'Personal Info', icon: User },
                { id: 'addresses', label: 'My Addresses', icon: MapPin },
                { id: 'orders', label: 'Order History', icon: Package },
              ].map((item) => (
                <button
                  key={item.id}
                  onClick={() => setActiveTab(item.id)}
                  className={`w-full flex items-center gap-3 px-6 py-4 text-sm font-bold transition-all ${
                    activeTab === item.id 
                    ? 'bg-teal-50 text-teal-600 border-r-4 border-teal-600' 
                    : 'text-slate-500 hover:bg-slate-50'
                  }`}
                >
                  <item.icon className={`w-5 h-5 ${activeTab === item.id ? 'text-teal-600' : 'text-slate-400'}`} />
                  {item.label}
                  <ChevronRight className={`ml-auto w-4 h-4 ${activeTab === item.id ? 'opacity-100' : 'opacity-0'}`} />
                </button>
              ))}
            </nav>
          </div>

          {/* RIGHT COLUMN: DYNAMIC CONTENT AREA */}
          <div className="lg:col-span-8 xl:col-span-9">

            {/* 1. PERSONAL INFO TAB */}
            {activeTab === 'profile' && (
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-bottom-4 duration-300">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                  <h3 className="text-lg font-bold text-slate-900">Personal Information</h3>
                  <button
                    onClick={editMode ? handleSaveProfile : () => setEditMode(true)}
                    className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${
                      editMode ? 'bg-teal-600 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                    }`}
                  >
                    {editMode ? 'Save Changes' : 'Edit Profile'}
                  </button>
                </div>
                <div className="p-8">
                  <div className="grid md:grid-cols-2 gap-x-8 gap-y-6">
                    <InputField label="Full Name" value={profileData.fullName} disabled={!editMode} 
                      onChange={v => setProfileData({...profileData, fullName: v})} />
                    <InputField label="Email Address" value={profileData.email} disabled={true} note="Cannot be changed" />
                    <InputField label="Mobile Number" value={profileData.mobile} disabled={!editMode} 
                      onChange={v => setProfileData({...profileData, mobile: v})} />

                    <div className="space-y-2">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Gender</label>
                      <select
                        value={profileData.gender || ''}
                        onChange={e => setProfileData({ ...profileData, gender: e.target.value })}
                        disabled={!editMode}
                        className="w-full h-12 px-4 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-teal-500/20 focus:border-teal-500 outline-none transition-all disabled:opacity-60"
                      >
                        <option value="">Select Gender</option>
                        <option value="Male">Male</option>
                        <option value="Female">Female</option>
                        <option value="Other">Other</option>
                      </select>
                    </div>
                  </div>

                  {editMode && (
                    <div className="mt-8 flex gap-3">
                      <button onClick={handleSaveProfile} className="px-8 py-3 bg-teal-600 text-white rounded-xl font-bold hover:bg-teal-700 transition-all shadow-lg shadow-teal-200">
                        {loading ? 'Saving...' : 'Confirm Updates'}
                      </button>
                      <button onClick={() => setEditMode(false)} className="px-8 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-all">
                        Cancel
                      </button>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* 2. ADDRESSES TAB */}
            {activeTab === 'addresses' && (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
                <div className="flex justify-between items-center">
                  <h3 className="text-xl font-bold text-slate-900">Saved Addresses</h3>
                  <button onClick={() => {/* your existing add logic */}} className="flex items-center gap-2 px-4 py-2 bg-teal-600 text-white rounded-lg text-sm font-bold hover:bg-teal-700 transition-all">
                    <Plus className="w-4 h-4" /> Add New
                  </button>
                </div>

                <div className="grid md:grid-cols-2 gap-4">
                  {profileData.addresses?.map((addr) => (
                    <div key={addr.id} className="group bg-white p-5 rounded-2xl border border-slate-200 hover:border-teal-500 transition-all relative">
                      <div className="flex justify-between items-start mb-2">
                        <span className={`px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter ${addr.IsDefault ? 'bg-teal-100 text-teal-700' : 'bg-slate-100 text-slate-500'}`}>
                          {addr.label || 'Home'}
                        </span>
                        <button className="opacity-0 group-hover:opacity-100 text-rose-500 p-1 hover:bg-rose-50 rounded transition-all">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                      <p className="text-sm text-slate-600 leading-relaxed font-medium">
                        {addr.AddressLine1}, {addr.City}, {addr.State} - {addr.PostalCode}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* 3. ORDERS TAB */}
            {activeTab === 'orders' && (
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-300">
                <div className="p-6 border-b border-slate-100">
                  <h3 className="text-lg font-bold text-slate-900">Order History</h3>
                </div>
                <div className="divide-y divide-slate-100">
                  {orders.map((order) => (
                    <div key={order.id} className="p-6 flex flex-wrap items-center justify-between gap-4 hover:bg-slate-50 transition-colors">
                      <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500">
                          <Package className="w-6 h-6" />
                        </div>
                        <div>
                          <p className="font-bold text-slate-900">Order #{order.id.toString().slice(-6)}</p>
                          <p className="text-xs text-slate-400 font-medium">{new Date(order.orderDate).toLocaleDateString()}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-8">
                        <div className="text-right">
                          <p className="font-bold text-teal-600">₹{order.totalAmount.toLocaleString()}</p>
                          <p className={`text-[10px] font-black uppercase ${
                            order.status === 'Delivered' ? 'text-emerald-500' : 'text-amber-500'
                          }`}>{order.status}</p>
                        </div>
                        <button onClick={() => setCurrentPage('orders')} className="p-2 hover:bg-white rounded-full border border-slate-200 shadow-sm transition-all">
                          <ChevronRight className="w-5 h-5 text-slate-400" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

          </div>
        </div>
      </main>
    </div>
  );
};

// Reusable Input Component to keep code clean
const InputField = ({ label, value, disabled, onChange, note }) => (
  <div className="space-y-2">
    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">{label}</label>
    <input
      value={value || ''}
      onChange={e => onChange?.(e.target.value)}
      disabled={disabled}
      className="w-full h-12 px-4 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-teal-500/10 focus:border-teal-500 outline-none transition-all disabled:opacity-60 font-medium text-slate-700"
    />
    {note && <p className="text-[10px] text-slate-400 font-medium italic">*{note}</p>}
  </div>
);

export default ProfilePage;
